10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
