46	type QuoteResult = { premium: number };
47	type ClaimResult = { payout: number; remainingCap: number };
48	type StepResult = QuoteResult | ClaimResult;
49	
50	const MAIN_ITEM_BASE: Record<string, number> = {
51	  sword: 100,
52	  amulet: 60,
53	  staff: 80,
54	  potion: 40,
55	};
56	
57	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
58	const COMPONENT_BASE = 25;
59	const BLOCK_SIZE = 3;
60	const BLOCK_BASE = 60;
61	
62	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
63	  sword: 1000,
64	  amulet: 600,
65	  staff: 800,
66	  potion: 400,
67	};
68	const COMPONENT_INSURANCE_VALUE = 250;
69	
70	const DEDUCTIBLE = 100;
71	const CAP_MULTIPLIER = 2;
72	
73	const PROCESSING_FEE = 5;
74	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
75	const CURSED_SURCHARGE_RATE = 0.5;
76	const HIGH_ENCHANTMENT_THRESHOLD = 5;
77	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
78	const LOYALTY_THRESHOLD_YEARS = 2;
79	const LOYALTY_DISCOUNT_RATE = 0.2;
80	const FOLLOWUP_DISCOUNT_RATE = 0.15;
81	
82	const componentGroupBase = (count: number): number => {
83	  if (count === BLOCK_SIZE) return BLOCK_BASE;
84	  return count * COMPONENT_BASE;
85	};
86	
87	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
88	
89	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
90	
91	const sumMainItems = (items: Item[]): number =>
92	  mainItems(items).reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
93	
94	const countByType = (items: Item[]): Record<string, number> => {
95	  const counts: Record<string, number> = {};
96	  for (const item of items) {
97	    counts[item.type] = (counts[item.type] ?? 0) + 1;
98	  }
99	  return counts;
100	};
101	
102	const sumComponentGroups = (items: Item[]): number => {
103	  const counts = countByType(items.filter(isComponent));
104	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
105	};
106	
107	const policyBasePremium = (items: Item[]): number =>
108	  sumMainItems(items) + sumComponentGroups(items);
109	
110	const cursedSurcharge = (item: Item): number => {
111	  const base = MAIN_ITEM_BASE[item.type];
112	  return item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
113	};
114	
115	const highEnchantmentSurcharge = (item: Item): number => {
116	  const base = MAIN_ITEM_BASE[item.type];
117	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
118	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
119	    : 0;
120	};
121	
122	const itemSurcharges = (items: Item[]): number =>
123	  mainItems(items).reduce(
124	    (total, item) => total + cursedSurcharge(item) + highEnchantmentSurcharge(item),
125	    0,
126	  );
127	
128	const loyaltyDiscount = (base: number, customer: Customer): number =>
129	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
130	
131	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
132	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
133	
134	const adjustedPremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
135	  const base = policyBasePremium(items);
136	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
137	  return (
138	    base +
139	    firstInsuranceSurcharge -
140	    loyaltyDiscount(base, customer) -
141	    followUpDiscount(base, isFollowUp) +
142	    itemSurcharges(items)
143	  );
144	};
145	
146	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number =>
147	  Math.ceil(adjustedPremium(step.items, customer, isFollowUp)) + PROCESSING_FEE;
148	
149	const itemInsuranceValue = (item: Item): number =>
150	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INSURANCE_VALUE[item.type];
151	
152	const insuranceSum = (items: Item[]): number =>
153	  items.reduce((total, item) => total + itemInsuranceValue(item), 0);
154	
155	const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
156	
157	const processClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
158	  const requested = step.incident.damages.reduce((total, damage) => total + damagePayout(damage), 0);
159	  const payout = Math.min(requested, policy.remainingCap);
160	  policy.remainingCap -= payout;
161	  return { payout, remainingCap: policy.remainingCap };
162	};
163	
164	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
165	  let quoteCount = 0;
166	  const policies: Policy[] = [];
167	  const results = scenario.steps.map((step, index): StepResult => {
168	    if (step.op === "claim") {
169	      return processClaim(step, policies[step.policy]);
170	    }
171	    const isFollowUp = quoteCount > 0;
172	    quoteCount += 1;
173	    const cap = insuranceSum(step.items) * CAP_MULTIPLIER;
174	    policies[index] = { items: step.items, cap, remainingCap: cap };
175	    return { premium: quotePremium(step, scenario.customer, isFollowUp) };
176	  });
177	  return { results };
178	};
